import { useState, useEffect } from "react";

const WHATSAPP = "919199414461";
const ADMIN_PWD = "Surya@2024";

const IMGS = {
  tata: "data:image/jpeg;base64,",
  kamdhenu: "data:image/jpeg;base64,",
  ultratech: "data:image/jpeg;base64,",
  prism: "data:image/jpeg;base64,",
  sand: "data:image/jpeg;base64,",
  bricks: "data:image/jpeg;base64,",
  stones: "data:image/jpeg;base64,",
};

const BASE_PRODUCTS = [
  { id: "b1", name: "Fly Ash Bricks Class A", category: "bricks", price: 4200, unit: "1000 pcs", brand: "Local Plant", img: IMGS.bricks },
  { id: "s1", name: "River Sand (Washed)", category: "sand", price: 2800, unit: "brass (100 cft)", brand: "Sourced", img: IMGS.sand },
  { id: "st1", name: "20mm Blue Metal Aggregate", category: "stones", price: 1800, unit: "brass (100 cft)", brand: "Quarry Direct", img: IMGS.stones },
  { id: "st2", name: "40mm Stone Aggregate", category: "stones", price: 1600, unit: "brass (100 cft)", brand: "Quarry Direct", img: IMGS.stones },
  { id: "t1", name: "Fe-550D TMT Bars", category: "tmt", price: 68500, unit: "metric tonne", brand: "TATA Tiscon", img: IMGS.tata },
  { id: "t2", name: "Fe-500 TMT Bars", category: "tmt", price: 65000, unit: "metric tonne", brand: "Kamdhenu", img: IMGS.kamdhenu },
  { id: "c2", name: "OPC 53 Grade Cement", category: "cement", price: 395, unit: "50kg bag", brand: "UltraTech", img: IMGS.ultratech },
  { id: "c3", name: "Champion Plus Cement", category: "cement", price: 370, unit: "50kg bag", brand: "PRISM", img: IMGS.prism },
];

const CATS = [
  { id: "all", label: "All" }, { id: "bricks", label: "Bricks" }, { id: "sand", label: "Sand" },
  { id: "stones", label: "Stones" }, { id: "tmt", label: "TMT Bars" }, { id: "cement", label: "Cement" },
];

const fmt = (n) => n >= 100000 ? `\u20b9${(n/100000).toFixed(1)}L` : `\u20b9${n.toLocaleString("en-IN")}`;
const genOTP = () => String(Math.floor(100000 + Math.random() * 900000));

const LS = {
  get: (k) => { try { const v = localStorage.getItem(k); return v ? JSON.parse(v) : null; } catch { return null; } },
  set: (k, v) => { try { localStorage.setItem(k, JSON.stringify(v)); } catch {} },
  del: (k) => { try { localStorage.removeItem(k); } catch {} },
};

export default function App() {
  const [products, setProducts] = useState(() => {
    const saved = LS.get("se_prod3");
    return saved ? BASE_PRODUCTS.map(p => { const s = saved.find(x => x.id === p.id); return s ? { ...p, price: s.price } : p; }) : BASE_PRODUCTS;
  });
  const [cart, setCart] = useState([]);
  const [qtys, setQtys] = useState({});
  const [cat, setCat] = useState("all");
  const [toast, setToast] = useState(null);
  const [view, setView] = useState("store");
  const [adminTab, setAdminTab] = useState("orders");
  const [orders, setOrders] = useState(() => LS.get("se_ord") || []);
  const [adminPwd, setAdminPwd] = useState("");
  const [loginErr, setLoginErr] = useState("");
  const [showOrderModal, setShowOrderModal] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authStep, setAuthStep] = useState("main");
  const [authForm, setAuthForm] = useState({ name: "", phone: "", password: "", newPassword: "", otp: "" });
  const [authErr, setAuthErr] = useState("");
  const [pendingOTP, setPendingOTP] = useState("");
  const [pendingPhone, setPendingPhone] = useState("");
  const [currentUser, setCurrentUser] = useState(() => LS.get("se_session"));
  const [form, setForm] = useState(() => { const u = LS.get("se_session"); return u ? { name: u.name, phone: u.phone, address: u.address || "" } : { name: "", phone: "", address: "" }; });
  const [editPrices, setEditPrices] = useState({});
  const [priceSaved, setPriceSaved] = useState(false);

  useEffect(() => { if (currentUser) { const c = LS.get(`cart_${currentUser.phone}`) || []; if (c.length) setCart(c); } }, []);

  const toast2 = (msg) => { setToast(msg); setTimeout(() => setToast(null), 3000); };
  const getQ = (id) => qtys[id] || 1;
  const cartCount = cart.reduce((s, i) => s + i.qty, 0);
  const cartTotal = cart.reduce((s, i) => s + i.price * i.qty, 0);
  const filtered = products.filter(p => cat === "all" || p.category === cat);
  const resetAuth = () => { setAuthStep("main"); setAuthForm({ name: "", phone: "", password: "", newPassword: "", otp: "" }); setAuthErr(""); setPendingOTP(""); setPendingPhone(""); };
  const openAuth = () => { resetAuth(); setShowAuthModal(true); };

  const addToCart = (p) => {
    const q = getQ(p.id);
    const nc = (() => { const ex = cart.find(i => i.id === p.id); return ex ? cart.map(i => i.id === p.id ? { ...i, qty: i.qty + q } : i) : [...cart, { ...p, qty: q }]; })();
    setCart(nc); if (currentUser) LS.set(`cart_${currentUser.phone}`, nc);
    toast2(`${p.brand} added to cart!`);
  };
  const updateCart = (nc) => { setCart(nc); if (currentUser) LS.set(`cart_${currentUser.phone}`, nc); };

  const loginUser = (user) => {
    LS.set("se_session", user); setCurrentUser(user);
    setForm({ name: user.name, phone: user.phone, address: user.address || "" });
    const sc = LS.get(`cart_${user.phone}`) || [];
    if (sc.length) { setCart(sc); toast2(`Welcome back, ${user.name}! Cart restored.`); } else toast2(`Welcome, ${user.name}!`);
    setShowAuthModal(false); resetAuth();
  };

  const handlePwdLogin = () => {
    setAuthErr(""); if (!authForm.phone || !authForm.password) { setAuthErr("Fill both fields"); return; }
    const u = (LS.get("se_users") || {})[authForm.phone];
    if (!u || u.pwd !== authForm.password) { setAuthErr("Invalid phone or password"); return; }
    loginUser({ name: u.name, phone: u.phone, address: u.address || "" });
  };
  const sendLoginOTP = () => {
    setAuthErr(""); if (!/^[0-9]{10}$/.test(authForm.phone)) { setAuthErr("Valid 10-digit phone required"); return; }
    if (!(LS.get("se_users") || {})[authForm.phone]) { setAuthErr("Phone not registered. Sign up first."); return; }
    const otp = genOTP(); setPendingOTP(otp); setPendingPhone(authForm.phone); setAuthStep("otp-verify");
    toast2(`OTP: ${otp}  (Demo mode)`);
  };
  const verifyLoginOTP = () => { setAuthErr(""); if (authForm.otp !== pendingOTP) { setAuthErr("Incorrect OTP"); return; } const u = (LS.get("se_users") || {})[pendingPhone]; loginUser({ name: u.name, phone: u.phone, address: u.address || "" }); };
  const sendSignupOTP = () => {
    setAuthErr(""); if (!authForm.name.trim()) { setAuthErr("Name required"); return; }
    if (!/^[0-9]{10}$/.test(authForm.phone)) { setAuthErr("Valid 10-digit phone required"); return; }
    if (authForm.password.length < 4) { setAuthErr("Password min 4 chars"); return; }
    if ((LS.get("se_users") || {})[authForm.phone]) { setAuthErr("Phone already registered"); return; }
    const otp = genOTP(); setPendingOTP(otp); setPendingPhone(authForm.phone); setAuthStep("signup-verify");
    toast2(`OTP: ${otp}  (Demo mode)`);
  };

  const directSignup = () => {
    setAuthErr("");
    if (!authForm.name.trim()) { setAuthErr("Name required"); return; }
    if (!/^[0-9]{10}$/.test(authForm.phone)) { setAuthErr("Valid 10-digit phone required"); return; }
    if (authForm.password.length < 4) { setAuthErr("Password min 4 chars"); return; }
    const users = LS.get("se_users") || {};
    if (users[authForm.phone]) { setAuthErr("Phone already registered. Login instead."); return; }
    const user = { name: authForm.name, phone: authForm.phone, address: "" };
    users[authForm.phone] = { ...user, pwd: authForm.password };
    LS.set("se_users", users);
    loginUser(user);
  };
  const verifySignupOTP = () => {
    setAuthErr(""); if (authForm.otp !== pendingOTP) { setAuthErr("Incorrect OTP"); return; }
    const users = LS.get("se_users") || {}; const user = { name: authForm.name, phone: pendingPhone, address: "" };
    users[pendingPhone] = { ...user, pwd: authForm.password }; LS.set("se_users", users); loginUser(user);
  };
  const sendForgotOTP = () => {
    setAuthErr(""); if (!/^[0-9]{10}$/.test(authForm.phone)) { setAuthErr("Valid 10-digit phone required"); return; }
    if (!(LS.get("se_users") || {})[authForm.phone]) { setAuthErr("Phone not registered"); return; }
    const otp = genOTP(); setPendingOTP(otp); setPendingPhone(authForm.phone); setAuthStep("forgot-otp");
    toast2(`OTP: ${otp}  (Demo mode)`);
  };
  const verifyForgotOTP = () => { setAuthErr(""); if (authForm.otp !== pendingOTP) { setAuthErr("Incorrect OTP"); return; } setAuthStep("forgot-reset"); };
  const resetPassword = () => {
    setAuthErr(""); if (authForm.newPassword.length < 4) { setAuthErr("Min 4 characters"); return; }
    const users = LS.get("se_users") || {}; users[pendingPhone].pwd = authForm.newPassword; LS.set("se_users", users);
    toast2("Password reset! Please login."); resetAuth();
  };
  const handleLogout = () => { if (currentUser) LS.set(`cart_${currentUser.phone}`, cart); LS.del("se_session"); setCurrentUser(null); setCart([]); toast2("Logged out"); };
  const placeOrder = () => {
    if (!form.name || !form.phone || !form.address) { toast2("Fill all fields"); return; }
    const order = { id: Date.now().toString(), date: new Date().toLocaleString("en-IN"), customer: { ...form }, items: cart.map(i => ({ name: i.name, brand: i.brand, qty: i.qty, unit: i.unit, price: i.price })), total: cartTotal };
    const no = [order, ...orders]; setOrders(no); LS.set("se_ord", no);
    if (currentUser) { const us = LS.get("se_users") || {}; if (us[currentUser.phone]) { us[currentUser.phone].address = form.address; LS.set("se_users", us); } LS.del(`cart_${currentUser.phone}`); }
    const lines = cart.map(i => `\u2022 ${i.brand} ${i.name} \u00d7 ${i.qty} ${i.unit} = ${fmt(i.price * i.qty)}`).join("\n");
    const msg = `*New Order \u2014 Surya Enterprises*\n\n*Name:* ${form.name}\n*Phone:* ${form.phone}\n*Address:* ${form.address}\n\n*Items:*\n${lines}\n\n*Total: ${fmt(cartTotal)}*\n\nKindly confirm this order.`;
    window.open(`https://wa.me/${WHATSAPP}?text=${encodeURIComponent(msg)}`, "_blank");
    setCart([]); setShowOrderModal(false); toast2("Order sent to WhatsApp!");
  };
  const deleteOrder = (id) => { const u = orders.filter(o => o.id !== id); setOrders(u); LS.set("se_ord", u); };
  const handleAdminLogin = () => { if (adminPwd === ADMIN_PWD) { setView("admin"); setLoginErr(""); setAdminPwd(""); } else setLoginErr("Incorrect password."); };
  const savePrices = () => {
    const u = products.map(p => editPrices[p.id] !== undefined ? { ...p, price: Number(editPrices[p.id]) } : p);
    setProducts(u); LS.set("se_prod3", u.map(p => ({ id: p.id, price: p.price })));
    setEditPrices({}); setPriceSaved(true); setTimeout(() => setPriceSaved(false), 2500);
  };
  const nb = (a) => ({ background: "none", border: "none", borderBottom: a ? "2px solid #B84A1A" : "2px solid transparent", padding: "9px 14px", cursor: "pointer", color: a ? "#F0D49A" : "#9A8060", fontSize: 12, whiteSpace: "nowrap" });
  const inp = { width: "100%", padding: "10px 12px", borderRadius: 7, border: "1px solid #ddd", fontSize: 13, boxSizing: "border-box" };
  const sbtn = (bg, color) => ({ width: "100%", marginTop: 10, padding: "12px", background: bg, border: bg === "none" ? "1px solid #ddd" : "none", borderRadius: 7, color, fontSize: 14, cursor: "pointer", fontWeight: 600 });
  const OTPBox = ({ onVerify, onResend, label }) => (
    <div>
      <div style={{ background: "#fff8f0", border: "1px solid #f0ddd0", borderRadius: 8, padding: "12px", marginBottom: 14, fontSize: 12, color: "#B84A1A", lineHeight: 1.6 }}>
        Demo mode: OTP shown in notification. In production, it will be sent via SMS.
      </div>
      <div style={{ fontSize: 12, color: "#666", marginBottom: 6 }}>Enter 6-digit OTP</div>
      <input value={authForm.otp} onChange={e => setAuthForm(x => ({ ...x, otp: e.target.value }))} onKeyDown={e => e.key === "Enter" && onVerify()} maxLength={6} placeholder="- - - - - -" style={{ ...inp, letterSpacing: 8, fontSize: 18, textAlign: "center" }} />
      {authErr && <div style={{ color: "#E24B4A", fontSize: 12, marginTop: 8 }}>{authErr}</div>}
      <button onClick={onVerify} style={sbtn("#B84A1A", "#fff")}>{label}</button>
      <button onClick={onResend} style={{ ...sbtn("none", "#B84A1A"), border: "1px solid #B84A1A" }}>Resend OTP</button>
      <button onClick={() => { setAuthStep("main"); setAuthErr(""); }} style={sbtn("none", "#888")}>Back</button>
    </div>
  );

  if (view === "store") return (
    <div style={{ fontFamily: "sans-serif", background: "#f5f3ef", minHeight: "100vh" }}>
      {toast && <div style={{ position: "fixed", bottom: 24, left: "50%", transform: "translateX(-50%)", background: "#2D4A22", color: "#D4EAB8", padding: "10px 22px", borderRadius: 6, fontSize: 13, zIndex: 9999, whiteSpace: "nowrap" }}>{toast}</div>}
      {showAuthModal && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.65)", zIndex: 2000, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
          <div style={{ background: "#fff", borderRadius: 14, padding: "28px 24px", width: "100%", maxWidth: 380, maxHeight: "90vh", overflowY: "auto" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
              <div style={{ fontFamily: "Georgia,serif", fontSize: 18, color: "#B84A1A" }}>
                {{"main":"Welcome","otp-login":"Login with OTP","otp-verify":"Verify OTP","signup":"Create Account","signup-verify":"Verify Number","forgot-step1":"Forgot Password","forgot-otp":"Enter OTP","forgot-reset":"New Password"}[authStep]}
              </div>
              <button onClick={() => { setShowAuthModal(false); resetAuth(); }} style={{ background: "none", border: "none", fontSize: 22, cursor: "pointer", color: "#aaa" }}>x</button>
            </div>
            {authStep === "main" && (
              <div>
                <div style={{ fontSize: 12, color: "#666", marginBottom: 6 }}>Phone Number</div>
                <input value={authForm.phone} onChange={e => setAuthForm(x => ({ ...x, phone: e.target.value }))} placeholder="10-digit mobile" style={inp} />
                <div style={{ fontSize: 12, color: "#666", margin: "12px 0 6px" }}>Password</div>
                <input type="password" value={authForm.password} onChange={e => setAuthForm(x => ({ ...x, password: e.target.value }))} onKeyDown={e => e.key === "Enter" && handlePwdLogin()} placeholder="Password" style={inp} />
                {authErr && <div style={{ color: "#E24B4A", fontSize: 12, marginTop: 8 }}>{authErr}</div>}
                <button onClick={handlePwdLogin} style={sbtn("#B84A1A", "#fff")}>Login</button>
                <div style={{ textAlign: "center", margin: "10px 0 4px", fontSize: 12, color: "#bbb" }}>or</div>
                <button onClick={() => { setAuthErr(""); setAuthStep("otp-login"); }} style={{ ...sbtn("none", "#B84A1A"), border: "1px solid #B84A1A" }}>Login with OTP</button>
                <div style={{ display: "flex", justifyContent: "space-between", marginTop: 14 }}>
                  <button onClick={() => { setAuthErr(""); setAuthStep("forgot-step1"); }} style={{ background: "none", border: "none", fontSize: 12, color: "#B84A1A", cursor: "pointer", textDecoration: "underline" }}>Forgot Password?</button>
                  <button onClick={() => { setAuthErr(""); setAuthStep("signup"); }} style={{ background: "none", border: "none", fontSize: 12, cursor: "pointer" }}>New? <b style={{ color: "#B84A1A" }}>Sign Up</b></button>
                </div>
              </div>
            )}
            {authStep === "otp-login" && (
              <div>
                <div style={{ fontSize: 12, color: "#666", marginBottom: 6 }}>Registered Phone</div>
                <input value={authForm.phone} onChange={e => setAuthForm(x => ({ ...x, phone: e.target.value }))} placeholder="10-digit mobile" style={inp} />
                {authErr && <div style={{ color: "#E24B4A", fontSize: 12, marginTop: 8 }}>{authErr}</div>}
                <button onClick={sendLoginOTP} style={sbtn("#B84A1A", "#fff")}>Send OTP</button>
                <button onClick={() => { setAuthStep("main"); setAuthErr(""); }} style={sbtn("none", "#888")}>Back</button>
              </div>
            )}
            {authStep === "otp-verify" && <OTPBox onVerify={verifyLoginOTP} onResend={() => { const o = genOTP(); setPendingOTP(o); toast2(`New OTP: ${o}`); }} label="Verify & Login" />}
            {authStep === "signup" && (
              <div>
                {[["name","Full Name","Your name"],["phone","Phone Number","10-digit mobile"],["password","Create Password","Min 4 characters"]].map(([f,label,ph]) => (
                  <div key={f} style={{ marginBottom: 12 }}>
                    <div style={{ fontSize: 12, color: "#666", marginBottom: 6 }}>{label}</div>
                    <input type={f === "password" ? "password" : "text"} value={authForm[f]} onChange={e => setAuthForm(x => ({ ...x, [f]: e.target.value }))} placeholder={ph} style={inp} />
                  </div>
                ))}
                {authErr && <div style={{ color: "#E24B4A", fontSize: 12, marginTop: 4 }}>{authErr}</div>}
                <button onClick={directSignup} style={sbtn("#B84A1A", "#fff")}>Create Account</button>
                <button onClick={() => { setAuthStep("main"); setAuthErr(""); }} style={sbtn("none", "#888")}>Back</button>
              </div>
            )}
            
            {authStep === "forgot-step1" && (
              <div>
                <p style={{ fontSize: 13, color: "#666", marginBottom: 14, lineHeight: 1.6 }}>Enter your registered phone number to receive an OTP for password reset.</p>
                <div style={{ fontSize: 12, color: "#666", marginBottom: 6 }}>Phone Number</div>
                <input value={authForm.phone} onChange={e => setAuthForm(x => ({ ...x, phone: e.target.value }))} placeholder="10-digit mobile" style={inp} />
                {authErr && <div style={{ color: "#E24B4A", fontSize: 12, marginTop: 8 }}>{authErr}</div>}
                <button onClick={sendForgotOTP} style={sbtn("#B84A1A", "#fff")}>Send OTP</button>
                <button onClick={() => { setAuthStep("main"); setAuthErr(""); }} style={sbtn("none", "#888")}>Back</button>
              </div>
            )}
            {authStep === "forgot-otp" && <OTPBox onVerify={verifyForgotOTP} onResend={() => { const o = genOTP(); setPendingOTP(o); toast2(`New OTP: ${o}`); }} label="Verify OTP" />}
            {authStep === "forgot-reset" && (
              <div>
                <div style={{ fontSize: 13, color: "#25A244", marginBottom: 14, fontWeight: 600 }}>OTP verified! Set your new password.</div>
                <div style={{ fontSize: 12, color: "#666", marginBottom: 6 }}>New Password</div>
                <input type="password" value={authForm.newPassword} onChange={e => setAuthForm(x => ({ ...x, newPassword: e.target.value }))} onKeyDown={e => e.key === "Enter" && resetPassword()} placeholder="Min 4 characters" style={inp} />
                {authErr && <div style={{ color: "#E24B4A", fontSize: 12, marginTop: 8 }}>{authErr}</div>}
                <button onClick={resetPassword} style={sbtn("#25A244", "#fff")}>Reset Password</button>
              </div>
            )}
          </div>
        </div>
      )}
      {showOrderModal && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.65)", zIndex: 2000, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
          <div style={{ background: "#fff", borderRadius: 12, padding: "28px 24px", width: "100%", maxWidth: 400 }}>
            <div style={{ fontFamily: "Georgia,serif", fontSize: 17, color: "#B84A1A", marginBottom: 16 }}>Confirm Order</div>
            {[["name","Your Name"],["phone","Phone"],["address","Delivery Address"]].map(([f,label]) => (
              <div key={f} style={{ marginBottom: 14 }}>
                <div style={{ fontSize: 12, color: "#666", marginBottom: 5 }}>{label}</div>
                {f === "address" ? <textarea value={form[f]} onChange={e => setForm(x => ({ ...x, [f]: e.target.value }))} rows={2} style={{ width: "100%", padding: "9px 12px", borderRadius: 6, border: "1px solid #ddd", fontSize: 13, resize: "none", boxSizing: "border-box" }} /> : <input value={form[f]} onChange={e => setForm(x => ({ ...x, [f]: e.target.value }))} style={{ width: "100%", padding: "9px 12px", borderRadius: 6, border: "1px solid #ddd", fontSize: 13, boxSizing: "border-box" }} />}
              </div>
            ))}
            <div style={{ borderTop: "1px solid #eee", paddingTop: 14 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
                <span style={{ fontSize: 13, color: "#666" }}>Total</span>
                <span style={{ fontSize: 16, fontWeight: 700, color: "#B84A1A" }}>{fmt(cartTotal)}</span>
              </div>
              <div style={{ display: "flex", gap: 10 }}>
                <button onClick={() => setShowOrderModal(false)} style={{ flex: 1, padding: "10px", background: "none", border: "1px solid #ddd", borderRadius: 6, fontSize: 13, cursor: "pointer" }}>Cancel</button>
                <button onClick={placeOrder} style={{ flex: 2, padding: "10px", background: "#25D366", border: "none", borderRadius: 6, fontSize: 13, cursor: "pointer", color: "#fff", fontWeight: 600 }}>Send via WhatsApp</button>
              </div>
            </div>
          </div>
        </div>
      )}
      <div style={{ background: "#1C1008", borderBottom: "3px solid #B84A1A" }}>
        <div style={{ maxWidth: 1100, margin: "0 auto", padding: "0 16px", display: "flex", alignItems: "center", gap: 10, height: 56 }}>
          <div>
            <div style={{ display: "flex", alignItems: "baseline", gap: 5 }}>
              <span style={{ fontFamily: "Georgia,serif", fontSize: 20, fontWeight: 700, color: "#F0D49A", letterSpacing: 1 }}>SURYA</span>
              <span style={{ fontSize: 9, color: "#B89060", letterSpacing: 3, textTransform: "uppercase" }}>Enterprises</span>
            </div>
            <div style={{ fontSize: 8, color: "#7A6040", letterSpacing: 2, textTransform: "uppercase" }}>Building Materials - Siwan</div>
          </div>
          <div style={{ flex: 1 }} />
          {currentUser ? (
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{ background: "#B84A1A", borderRadius: "50%", width: 28, height: 28, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontSize: 12, fontWeight: 700 }}>{currentUser.name[0].toUpperCase()}</div>
              <span style={{ fontSize: 11, color: "#F0D49A", maxWidth: 70, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{currentUser.name}</span>
              <button onClick={handleLogout} style={{ background: "none", border: "0.5px solid rgba(255,255,255,0.2)", borderRadius: 4, padding: "3px 8px", cursor: "pointer", color: "#9A8060", fontSize: 10 }}>Logout</button>
            </div>
          ) : (
            <button onClick={openAuth} style={{ background: "none", border: "0.5px solid rgba(255,255,255,0.25)", borderRadius: 6, padding: "5px 12px", cursor: "pointer", color: "#F0D49A", fontSize: 11 }}>Login / Sign Up</button>
          )}
          {cartCount > 0 && (
            <button onClick={() => { if (!currentUser) openAuth(); else setShowOrderModal(true); }} style={{ background: "#25D366", border: "none", borderRadius: 6, padding: "7px 12px", cursor: "pointer", color: "#fff", fontSize: 12, display: "flex", alignItems: "center", gap: 5 }}>
              Cart <span style={{ background: "#fff", color: "#25D366", borderRadius: 10, padding: "1px 6px", fontSize: 11, fontWeight: 700 }}>{cartCount}</span>
            </button>
          )}
        </div>
        <div style={{ background: "rgba(0,0,0,0.3)" }}>
          <div style={{ maxWidth: 1100, margin: "0 auto", padding: "0 16px", display: "flex", overflowX: "auto" }}>
            {CATS.map(c => <button key={c.id} onClick={() => setCat(c.id)} style={nb(cat === c.id)}>{c.label}</button>)}
          </div>
        </div>
      </div>
      <div style={{ background: "linear-gradient(135deg,#2A1505,#3D1F08,#1C1008)", padding: "28px 16px" }}>
        <div style={{ maxWidth: 1100, margin: "0 auto" }}>
          <div style={{ fontSize: 10, color: "#B84A1A", letterSpacing: 4, textTransform: "uppercase", marginBottom: 6 }}>Trusted Since 2010 - Siwan's #1</div>
          <h1 style={{ fontFamily: "Georgia,serif", fontSize: 30, fontWeight: 700, color: "#F5E8D0", margin: "0 0 8px" }}>Build With Confidence.</h1>
          <p style={{ color: "#9A8060", fontSize: 13, margin: "0 0 14px", lineHeight: 1.7 }}>Premium construction materials delivered to your site in Siwan and surrounding districts.</p>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            {["Same-Day Delivery","GST Invoice","Bulk Pricing","Quality Assured"].map(t => (
              <span key={t} style={{ background: "rgba(184,74,26,0.15)", border: "0.5px solid rgba(184,74,26,0.4)", color: "#D4784A", padding: "3px 10px", borderRadius: 4, fontSize: 10 }}>{t}</span>
            ))}
          </div>
        </div>
      </div>
      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "24px 16px" }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", gap: 14 }}>
          {filtered.map(p => (
            <div key={p.id} style={{ background: "#fff", borderRadius: 10, border: "1px solid #e8e4de", overflow: "hidden", display: "flex", flexDirection: "column" }}>
              <div style={{ height: 160, overflow: "hidden" }}>
                <img src={p.img} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
              </div>
              <div style={{ padding: "12px 14px", flex: 1, display: "flex", flexDirection: "column", gap: 4 }}>
                <div style={{ fontSize: 10, color: "#B84A1A", letterSpacing: 1, textTransform: "uppercase", fontWeight: 600 }}>{p.brand}</div>
                <div style={{ fontSize: 13, fontWeight: 500 }}>{p.name}</div>
                <div style={{ display: "flex", alignItems: "baseline", gap: 5, marginTop: 4 }}>
                  <span style={{ fontFamily: "Georgia,serif", fontSize: 17, fontWeight: 700, color: "#B84A1A" }}>{fmt(p.price)}</span>
                  <span style={{ fontSize: 11, color: "#888" }}>/ {p.unit}</span>
                </div>
                <div style={{ marginTop: "auto", paddingTop: 10, display: "flex", gap: 7 }}>
                  <div style={{ display: "flex", alignItems: "center", border: "1px solid #ddd", borderRadius: 6, overflow: "hidden" }}>
                    <button onClick={() => setQtys(q => ({ ...q, [p.id]: Math.max(1, getQ(p.id)-1) }))} style={{ padding: "5px 9px", background: "none", border: "none", cursor: "pointer" }}>-</button>
                    <span style={{ padding: "5px 7px", fontSize: 13, minWidth: 20, textAlign: "center" }}>{getQ(p.id)}</span>
                    <button onClick={() => setQtys(q => ({ ...q, [p.id]: getQ(p.id)+1 }))} style={{ padding: "5px 9px", background: "none", border: "none", cursor: "pointer" }}>+</button>
                  </div>
                  <button onClick={() => addToCart(p)} style={{ flex: 1, padding: "7px", background: "#B84A1A", color: "#fff", border: "none", borderRadius: 6, fontSize: 12, cursor: "pointer", fontWeight: 600 }}>Add to Cart</button>
                </div>
              </div>
            </div>
          ))}
        </div>
        {cartCount > 0 && (
          <div style={{ position: "sticky", bottom: 16, background: "#1C1008", border: "1px solid #B84A1A", borderRadius: 10, padding: "12px 18px", display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 24 }}>
            <div>
              <div style={{ fontSize: 11, color: "#7A6040" }}>{cartCount} items</div>
              <div style={{ fontFamily: "Georgia,serif", fontSize: 17, color: "#F0D49A", fontWeight: 700 }}>{fmt(cartTotal)}</div>
            </div>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={() => updateCart([])} style={{ padding: "7px 12px", background: "none", border: "0.5px solid rgba(255,255,255,0.2)", borderRadius: 6, fontSize: 12, cursor: "pointer", color: "#9A8060" }}>Clear</button>
              <button onClick={() => { if (!currentUser) openAuth(); else setShowOrderModal(true); }} style={{ padding: "9px 18px", background: "#25D366", border: "none", borderRadius: 6, fontSize: 13, cursor: "pointer", color: "#fff", fontWeight: 600 }}>Order via WhatsApp</button>
            </div>
          </div>
        )}
      </div>
      <div style={{ background: "#1C1008", borderTop: "3px solid #B84A1A", padding: "28px 16px", marginTop: 32 }}>
        <div style={{ maxWidth: 1100, margin: "0 auto", display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))", gap: 24 }}>
          <div>
            <div style={{ fontFamily: "Georgia,serif", fontSize: 15, color: "#F0D49A", marginBottom: 8 }}>SURYA Enterprises</div>
            <div style={{ fontSize: 11, color: "#7A6040", lineHeight: 2 }}>Prop: Harendra Kumar Singh<br />GSTIN: 10CCZZPS6888P1Z6<br />Kapiya Jagir, Mahrajganj<br />Siwan, Bihar - 841238</div>
          </div>
          <div>
            <div style={{ fontSize: 10, color: "#B84A1A", letterSpacing: 2, textTransform: "uppercase", marginBottom: 8 }}>Contact</div>
            <div style={{ fontSize: 11, color: "#7A6040", lineHeight: 2 }}>+91 9199414461<br />info@suryaenterprises.com</div>
          </div>
          <div>
            <div style={{ fontSize: 10, color: "#B84A1A", letterSpacing: 2, textTransform: "uppercase", marginBottom: 8 }}>Hours</div>
            <div style={{ fontSize: 11, color: "#7A6040", lineHeight: 2 }}>Mon-Sat: 8AM-7PM<br />Sun: 9AM-4PM</div>
          </div>
        </div>
        <div style={{ maxWidth: 1100, margin: "14px auto 0", borderTop: "0.5px solid rgba(255,255,255,0.06)", paddingTop: 12, display: "flex", justifyContent: "space-between" }}>
          <span style={{ fontSize: 10, color: "#4A3020" }}>2025 Surya Enterprises</span>
          <button onClick={() => setView("admin-login")} style={{ background: "none", border: "none", fontSize: 10, color: "#3A2010", cursor: "pointer" }}>Admin</button>
        </div>
      </div>
    </div>
  );

  if (view === "admin-login") return (
    <div style={{ minHeight: "100vh", background: "#1C1008", display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ background: "#fff", borderRadius: 12, padding: "36px 32px", width: 300 }}>
        <div style={{ fontFamily: "Georgia,serif", fontSize: 22, color: "#B84A1A", marginBottom: 2 }}>SURYA</div>
        <div style={{ fontSize: 12, color: "#888", marginBottom: 24 }}>Admin Panel</div>
        <input type="password" value={adminPwd} onChange={e => setAdminPwd(e.target.value)} onKeyDown={e => e.key === "Enter" && handleAdminLogin()} placeholder="Admin password" style={{ width: "100%", padding: "10px 14px", borderRadius: 6, border: "1px solid #ddd", fontSize: 14, boxSizing: "border-box" }} />
        {loginErr && <div style={{ color: "#E24B4A", fontSize: 12, marginTop: 8 }}>{loginErr}</div>}
        <button onClick={handleAdminLogin} style={{ width: "100%", marginTop: 14, padding: "11px", background: "#B84A1A", border: "none", borderRadius: 6, color: "#fff", fontSize: 14, cursor: "pointer", fontWeight: 600 }}>Login</button>
        <button onClick={() => setView("store")} style={{ width: "100%", marginTop: 8, padding: "10px", background: "none", border: "1px solid #ddd", borderRadius: 6, color: "#666", fontSize: 13, cursor: "pointer" }}>Back to Store</button>
      </div>
    </div>
  );

  return (
    <div style={{ fontFamily: "sans-serif", background: "#f5f3ef", minHeight: "100vh" }}>
      {priceSaved && <div style={{ position: "fixed", bottom: 24, left: "50%", transform: "translateX(-50%)", background: "#2D4A22", color: "#D4EAB8", padding: "10px 22px", borderRadius: 6, fontSize: 13, zIndex: 9999 }}>Prices saved!</div>}
      <div style={{ background: "#1C1008", borderBottom: "3px solid #B84A1A", padding: "0 20px" }}>
        <div style={{ maxWidth: 1100, margin: "0 auto", display: "flex", alignItems: "center", height: 52 }}>
          <span style={{ fontFamily: "Georgia,serif", fontSize: 17, color: "#F0D49A", marginRight: 8 }}>SURYA Admin</span>
          <button onClick={() => setAdminTab("orders")} style={nb(adminTab === "orders")}>Orders {orders.length > 0 && <span style={{ background: "#B84A1A", color: "#fff", borderRadius: 10, padding: "1px 6px", fontSize: 10, marginLeft: 4 }}>{orders.length}</span>}</button>
          <button onClick={() => setAdminTab("prices")} style={nb(adminTab === "prices")}>Update Prices</button>
          <div style={{ flex: 1 }} />
          <button onClick={() => setView("store")} style={{ background: "none", border: "0.5px solid rgba(255,255,255,0.2)", borderRadius: 6, padding: "5px 12px", cursor: "pointer", color: "#9A8060", fontSize: 11 }}>Store</button>
        </div>
      </div>
      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "24px 20px" }}>
        {adminTab === "orders" && (
          <div>
            <div style={{ fontSize: 18, fontFamily: "Georgia,serif", marginBottom: 18 }}>Orders ({orders.length})</div>
            {orders.length === 0 ? <div style={{ background: "#fff", borderRadius: 12, border: "1px solid #e8e4de", padding: "56px 24px", textAlign: "center", color: "#888" }}>No orders yet.</div>
              : orders.map(order => (
                <div key={order.id} style={{ background: "#fff", borderRadius: 10, border: "1px solid #e8e4de", padding: "18px", marginBottom: 12 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 10 }}>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: 15 }}>{order.customer.name}</div>
                      <div style={{ fontSize: 12, color: "#666", marginTop: 2 }}>{order.customer.phone}</div>
                      <div style={{ fontSize: 12, color: "#666" }}>{order.customer.address}</div>
                      <div style={{ fontSize: 11, color: "#aaa", marginTop: 2 }}>{order.date}</div>
                    </div>
                    <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 8 }}>
                      <div style={{ fontFamily: "Georgia,serif", fontSize: 16, fontWeight: 700, color: "#B84A1A" }}>{fmt(order.total)}</div>
                      <button onClick={() => deleteOrder(order.id)} style={{ padding: "4px 12px", background: "none", border: "1px solid #E24B4A", borderRadius: 5, color: "#E24B4A", fontSize: 11, cursor: "pointer" }}>Delete</button>
                    </div>
                  </div>
                  <div style={{ borderTop: "1px solid #f0ece6", paddingTop: 10 }}>
                    {order.items.map((item, i) => (
                      <div key={i} style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "#666", padding: "2px 0" }}>
                        <span>{item.brand} {item.name} x{item.qty} {item.unit}</span>
                        <span style={{ color: "#1a1a1a", fontWeight: 500 }}>{fmt(item.price * item.qty)}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))
            }
          </div>
        )}
        {adminTab === "prices" && (
          <div>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
              <div style={{ fontSize: 18, fontFamily: "Georgia,serif" }}>Update Prices</div>
              <button onClick={savePrices} style={{ padding: "9px 22px", background: "#B84A1A", border: "none", borderRadius: 6, color: "#fff", fontSize: 13, cursor: "pointer", fontWeight: 600 }}>Save All</button>
            </div>
            {CATS.filter(c => c.id !== "all").map(cat => (
              <div key={cat.id} style={{ marginBottom: 24 }}>
                <div style={{ fontSize: 11, color: "#B84A1A", letterSpacing: 2, textTransform: "uppercase", marginBottom: 8 }}>{cat.label}</div>
                {products.filter(p => p.category === cat.id).map(p => (
                  <div key={p.id} style={{ background: "#fff", borderRadius: 8, border: "1px solid #e8e4de", padding: "12px 14px", marginBottom: 7, display: "flex", justifyContent: "space-between", alignItems: "center", gap: 12 }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 13, fontWeight: 500 }}>{p.brand} - {p.name}</div>
                      <div style={{ fontSize: 11, color: "#888" }}>per {p.unit}</div>
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{ color: "#888" }}>Rs.</span>
                      <input type="number" value={editPrices[p.id] !== undefined ? editPrices[p.id] : p.price} onChange={e => setEditPrices(ep => ({ ...ep, [p.id]: e.target.value }))} style={{ width: 110, padding: "8px 10px", borderRadius: 6, border: editPrices[p.id] !== undefined ? "2px solid #B84A1A" : "1px solid #ddd", fontSize: 14, textAlign: "right" }} />
                    </div>
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
